algorithm:
Modified greedy insertion with fallback empty-vehicle expansion per order: attempt each existing route in best-cost-first order, compute tentative cost delta using distance/time feasibility checks via AddShip/GenRoute, pick feasible best improvement; if none works, allocate a new vehicle starting at this order's origin.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx   int
		delta float64
		ok    bool
	}
	orderCount := len(oris)
	existingRoutes := make([]int, 0, MAXASSIGNS)
	for i := 0; i < dispatch.AssignsLen; i++ {
		if dispatch.Assigns[i].StationsLen >= 0 {
			existingRoutes = append(existingRoutes, i)
		}
	}
	for orderIdx := 0; orderIdx < orderCount; orderIdx++ {
		ori := oris[orderIdx]
		des := dess[orderIdx]
		shipID := total_ship + orderIdx
		bestCandidate := candidate{idx: -1, delta: 0.0, ok: false}
		for _, rIdx := range existingRoutes {
			prevCost := dispatch.Assigns[rIdx].Cost
			addOk := dispatch.Assigns[rIdx].AddShip(shipID, ori, des)
			if addOk {
				dispatch.Assigns[rIdx].GenRoute()
				newCost := dispatch.Assigns[rIdx].Cost
				if newCost >= 0 {
					delta := newCost - prevCost
					if !bestCandidate.ok || delta < bestCandidate.delta {
						bestCandidate.idx = rIdx
						bestCandidate.delta = delta
						bestCandidate.ok = true
					}
				}
			}
			if !addOk || dispatch.Assigns[rIdx].Cost < 0 {
				dispatch.Assigns[rIdx].RemoveShip(shipID)
				dispatch.Assigns[rIdx].GenRoute()
			} else {
				dispatch.Assigns[rIdx].RemoveShip(shipID)
				dispatch.Assigns[rIdx].GenRoute()
			}
		}
		if bestCandidate.ok {
			dispatch.Assigns[bestCandidate.idx].AddShip(shipID, ori, des)
			dispatch.Assigns[bestCandidate.idx].GenRoute()
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				newIdx := dispatch.AssignsLen
				success := dispatch.Assigns[newIdx].AddShip(shipID, ori, des)
				if success {
					dispatch.Assigns[newIdx].GenRoute()
					if dispatch.Assigns[newIdx].Cost >= 0 {
						dispatch.AssignsLen++
						existingRoutes = append(existingRoutes, newIdx)
					} else {
						dispatch.Assigns[newIdx].RemoveShip(shipID)
						dispatch.Assigns[newIdx].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

