My algorithm uses a greedy insertion heuristic that evaluates all existing assigns plus one potential new empty assign for each order, scoring candidates by the marginal increase in travel distance weighted by time window feasibility penalty, then selects the best feasible candidate without skipping orders.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx       int
		isNew     bool
		deltaDist float64
		feasible  bool
		costBefore float64
		assignCopy Assign
	}
	newDispatch := dispatch
	for jj := range oris {
		bestCandidate := candidate{idx: -1, deltaDist: 1e100}
		orderId := total_ship + jj
		ori := oris[jj]
		des := dess[jj]

		for ii := 0; ii <= newDispatch.AssignsLen; ii++ {
			if ii == MAXASSIGNS {
				continue
			}
			currentAssign := &newDispatch.Assigns[ii]
			var testAssign Assign
			testAssign = *currentAssign
			costBefore := testAssign.Cost
			if testAssign.AddShip(orderId, ori, des) {
				testAssign.GenRoute()
				if testAssign.Cost >= 0 {
					delta := testAssign.Cost - costBefore
					score := delta
					isBetter := false
					if !bestCandidate.feasible && true {
						isBetter = true
					} else if bestCandidate.feasible && true {
						if score < bestCandidate.deltaDist {
							isBetter = true
						}
					}
					if isBetter {
						bestCandidate.idx = ii
						bestCandidate.isNew = (ii == newDispatch.AssignsLen)
						bestCandidate.deltaDist = score
						bestCandidate.feasible = true
						bestCandidate.costBefore = costBefore
						bestCandidate.assignCopy = testAssign
					}
				} else {
					testAssign.RemoveShip(orderId)
					testAssign.GenRoute()
				}
			}
		}

		if bestCandidate.idx >= 0 {
			targetIdx := bestCandidate.idx
			newDispatch.Assigns[targetIdx] = bestCandidate.assignCopy
			if bestCandidate.isNew && targetIdx == newDispatch.AssignsLen && newDispatch.AssignsLen < MAXASSIGNS {
				newDispatch.AssignsLen++
			}
		} else {
			if newDispatch.AssignsLen < MAXASSIGNS {
				emptyIdx := newDispatch.AssignsLen
				ok := newDispatch.Assigns[emptyIdx].AddShip(orderId, ori, des)
				if ok {
					newDispatch.Assigns[emptyIdx].GenRoute()
					if newDispatch.Assigns[emptyIdx].Cost >= 0 {
						newDispatch.AssignsLen++
					} else {
						newDispatch.Assigns[emptyIdx].RemoveShip(orderId)
						newDispatch.Assigns[emptyIdx].GenRoute()
					}
				}
			}
		}
	}
	newDispatch.RenewnTotalCost()
	return newDispatch

