algorithm:
New greedy regret-insertion heuristic that evaluates all feasible slots across existing routes plus optional new empty assign for each order, picks the slot minimizing marginal cost increase, and falls back to appending to a new empty assign if no feasible slot exists.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    nOrders := len(oris)
    for idx := 0; idx < nOrders; idx++ {
        shipID := total_ship + idx
        bestAssignIdx := -1
        bestPosBefore := -1
        bestMarginal := 1e100
        for ai := 0; ai <= dispatch.AssignsLen; ai++ {
            if ai == MAXASSIGNS { break }
            a := &dispatch.Assigns[ai]
            originalCost := a.Cost
            if a.GenRoute(); a.Cost < 0 { continue }
            m := a.StationsLen
            for pos := 0; pos <= m; pos++ {
                if pos == m && ai == dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
                    ok := a.AddShip(shipID, oris[idx], dess[idx])
                    if !ok { continue }
                    a.GenRoute()
                    if a.Cost >= 0 {
                        marg := a.Cost
                        if marg < bestMarginal {
                            bestMarginal = marg
                            bestAssignIdx = ai
                            bestPosBefore = pos
                        }
                    }
                    a.RemoveShip(shipID)
                    a.GenRoute()
                    continue
                }
                if pos < m || ai < dispatch.AssignsLen {
                    savedState := make([]interface{}, 0)
                    tmpAssign := *a
                    savedAssign := tmpAssign
                    ok := a.AddShip(shipID, oris[idx], dess[idx])
                    if !ok { continue }
                    a.GenRoute()
                    if a.Cost >= 0 {
                        marg := a.Cost - originalCost
                        if marg < bestMarginal {
                            bestMarginal = marg
                            bestAssignIdx = ai
                            bestPosBefore = pos
                        }
                    }
                    a.RemoveShip(shipID)
                    a.GenRoute()
                    *a = savedAssign
                }
            }
        }
        if bestAssignIdx != -1 {
            target := &dispatch.Assigns[bestAssignIdx]
            added := target.AddShip(shipID, oris[idx], dess[idx])
            if !added {
                target.Cost = -1
            }
            target.GenRoute()
            if target.Cost < 0 {
                target.RemoveShip(shipID)
                target.GenRoute()
                bestAssignIdx = -1
            }
        }
        if bestAssignIdx == -1 {
            if dispatch.AssignsLen < MAXASSIGNS {
                na := &dispatch.Assigns[dispatch.AssignsLen]
                added := na.AddShip(shipID, oris[idx], dess[idx])
                if added {
                    na.GenRoute()
                    if na.Cost >= 0 {
                        dispatch.AssignsLen++
                    } else {
                        na.RemoveShip(shipID)
                        na.GenRoute()
                    }
                }
            }
        }
    }
    dispatch.RenewnTotalCost()
    return dispatch

